class Board:
    def __init__(self):
        self.grid = [[None for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        # Place pieces on the board
        for i in range(3, 5):
            for j in range(0, 8, 2):
                self.grid[i][j] = Piece("White", False)
                self.grid[5 - i][7 - j] = Piece("Black", False)

    def __str__(self):
        return self.get_board_string()

    def get_board_string(self):
        board_str = "  a b c d e f g h\n"
        for i in range(8):
            board_str += f"{i + 1} |"
            for j in range(8):
                if self.grid[i][j]:
                    piece_type = 'K' if self.grid[i][j].is_king else 'P'
                    board_str += f" {piece_type}"
                else:
                    board_str += " ."
            board_str += "|\n"
        return board_str

    def get_piece_at(self, position):
        rank, file = ord(position[1]) - ord('1'), ord(position[0]) - ord('a')
        return self.grid[rank][file]

    def set_piece_at(self, position, piece):
        rank, file = ord(position[1]) - ord('1'), ord(position[0]) - ord('a')
        self.grid[rank][file] = piece

    def is_valid_move(self, move, player):
        from_pos, to_pos = move[:2], move[3:]
        from_piece = self.get_piece_at(from_pos)
        to_piece = self.get_piece_at(to_pos)

        if not from_piece or from_piece.color != player:
            return False
        if to_piece and to_piece.color == player:
            return False

        # Simple piece movement
        if abs(ord(from_pos[0]) - ord(to_pos[0])) == 1 and abs(int(from_pos[1]) - int(to_pos[1])) == 1:
