            intermediate_pos = chr((ord(from_pos[0]) + ord(to_pos[0])) // 2 + ord('a') - 97) + str((int(from_pos[1]) + int(to_pos[1])) // 2)
            return self.get_piece_at(intermediate_pos) and self.get_piece_at(intermediate_pos).color != player

        return False
